// 1. Get the global static data storage
const staticData = $getWorkflowStaticData('global');
if (!staticData.processedRecords) {
  staticData.processedRecords = {};
}

// 2. Get ALL incoming items
const items = $input.all();
const output = [];

for (const item of items) {
  const incoming = item.json;

  if (!incoming.website_url) {
    output.push({ json: { ...incoming, duplicate: false } });
    continue;
  }

  const key = String(incoming.website_url).trim().toLowerCase().replace(/\/$/, '');

  let isDuplicate = false;
  let finalRecord = { ...incoming };

  if (staticData.processedRecords[key] !== undefined) {
    isDuplicate = true;
    const existing = staticData.processedRecords[key];
    const mergeFields = ['row_number', 'company_name', 'website_url', 'market_category', 'run_id', 'record_key'];
    for (const field of mergeFields) {
      if ((finalRecord[field] === undefined || finalRecord[field] === '') && existing[field]) {
        finalRecord[field] = existing[field];
      }
    }
    staticData.processedRecords[key] = finalRecord;
  } else {
    staticData.processedRecords[key] = finalRecord;
  }

  output.push({
    json: {
      ...finalRecord,
      record_key: key,
      duplicate: isDuplicate
    }
  });
}

return output;

// Retrieve the input data
const items = $input.all();

let part1, part2;

// Check if the input came in as a single item containing an array, or as two separate n8n items
if (items.length === 1 && Array.isArray(items[0].json)) {
  part1 = items[0].json[0];
  part2 = items[0].json[1];
} else if (items.length >= 2) {
  part1 = items[0].json;
  part2 = items[1].json;
} else {
  throw new Error("Unexpected input structure. Expected an array with at least two objects.");
}

// Map the specific fields from the second part
const mappedPart2 = {
  profile_url: part2.url,
  normalized_url: part2.inputUrl || part2.url,
  full_name: part2.fullName,
  followers_count: part2.followersCount,
  biography: part2.biography
};

// Combine everything from part 1 with the mapped fields from part 2
const result = {
  ...part1,
  ...mappedPart2
};

// Return the merged object as a single n8n item
return [{ json: result }];
